    int m_width;
    int m_height;
public:
    Box(int width = 3, int height = 4)
        : m_width{ width }, m_height{ height }
    {}
    int area() const { return m_width * m_height; }
};

int main() {
    int w{}, h{};
    std::cin >> w >> h;
    Box b1{};
    Box b2{ w, h };
    std::cout << "Default area: " << b1.area() << "\n";
    std::cout << "Custom area: " << b2.area() << "\n";
}

